import React, { useState } from 'react';
import { Link } from 'react-router-dom';

export default function Header() {
  const [menuOpen, setMenuOpen] = useState(false);

  // Updated links array with the "Blog" link
  const links = [
    { name: "Home", href: "/" },
    { name: "Projects", href: "/projects" },
    { name: "Services", href: "/services" },
    { name: "About", href: "/about" },
    { name: "Contact", href: "/contact" },
    { name: "FAQ", href: "/faq" },
    <a href="#services">Services</a>

  ];

  return (
    <header className="main-header">
      <div className="header-container">
        <h1 className="logo-text">ProjectTime</h1>
        <button className="menu-toggle" onClick={() => setMenuOpen(!menuOpen)}>
          <span className="hamburger" />
          <span className="hamburger" />
          <span className="hamburger" />
        </button>
        <nav className={`nav-links ${menuOpen ? 'active' : ''}`}>
          {links.map((link) => (
            <Link key={link.name} to={link.href} className="nav-item" onClick={() => setMenuOpen(false)}>
              {link.name}
            </Link>
          ))}
        </nav>

        {/* Contact Info aligned to the Right */}
        <div className="contact-info">
  <ul className="contact-list">
    <li className="contact-item">
      <a href="tel:+918391808784">
        <i className="fas fa-phone-alt"></i> (+91) 8391808784
      </a>
    </li>
    <li className="contact-item">
      <a href="mailto:rupankargarai55@gmail.com">
        <i className="fas fa-envelope"></i> rupankargarai55@gmail.com
      </a>
    </li>
  </ul>
</div>
      </div>
    </header>
  );
}
